const event = $json;
const rawPayload = event.payload;
const parsedPayload = typeof rawPayload === 'string' ? (() => { try { return JSON.parse(rawPayload); } catch(e) { return {}; } })() : (rawPayload || {});

// Extraer información relevante del PR o commit
const pr = parsedPayload.pull_request || {};
const title = pr.title || parsedPayload.title || 'Unknown title';
const body = pr.body || parsedPayload.body || 'No description provided';
const actor = event.actor || parsedPayload.actor || 'system';
const repo = parsedPayload.repository ? parsedPayload.repository.name : (event.repo || 'unknown_repo');

return [{
  json: {
    correlation_id: event.correlation_id || `crs-${Date.now()}`,
    actor,
    repo,
    title,
    body,
    is_pr: !!parsedPayload.pull_request
  }
}];
